import pino from "pino";

export interface LoggerConfig {
  service: string;
  env: string;
  version: string;
}

export function createLogger({ service, env, version }: LoggerConfig) {
  return pino({
    level: process.env.LOG_LEVEL ?? "info",
    base: { service, environment: env, version },
    formatters: {
      level: (label) => ({ level: label }),
    },
    timestamp: pino.stdTimeFunctions.isoTime,
    redact: {
      paths: [
        "req.headers.authorization",
        "req.headers.cookie",
        "*.password",
        "*.token",
        "*.secret",
        "*.apiKey",
      ],
      censor: "[REDACTED]",
    },
  });
}

import { Hono } from "hono";
import pinoHttp from "pino-http";
import { logger } from "@charlybot/shared/observability/pino";

const app = new Hono();

app.use(pinoHttp({ logger }));

app.get("/health", (c) => c.json({ ok: true }));

export default app;

const pinoHttpMiddleware = pinoHttp({
  logger,
  customSuccessMessage: (req, res, val) =>
    `${req.method} ${req.url} → ${res.statusCode}`,
  customErrorMessage: (req, res, err) =>
    `${req.method} ${req.url} → ERROR: ${err.message}`,
  customAttributeKeys: {
    req: "request",
    res: "response",
    err: "error",
    responseTime: "latency_ms",
  },
  serializers: {
    req: (req) => ({
      method: req.method,
      url: req.url,
      headers: {
        host: req.headers.host,
        "user-agent": req.headers["user-agent"],
        "content-type": req.headers["content-type"],
      },
    }),
    res: (res) => ({ statusCode: res.statusCode }),
  },
});

import { logger } from "../../../utils/logger";

export async function handlePing(interaction: ChatInputCommandInteraction) {
  const childLogger = logger.child({
    interaction_id: interaction.id,
    user_id: interaction.user.id,
    guild_id: interaction.guildId,
    command: "ping",
  });

  childLogger.info("Ping command received");

  try {
    await interaction.reply({ content: "Pong!" });
    childLogger.info("Ping command completed");
  } catch (error) {
    childLogger.error(
      { error: error instanceof Error ? error.message : String(error) },
      "Ping command failed"
    );
  }
}

import { logger } from "@charlybot/shared/observability";

const prismaLogger = logger.child({ component: "prisma" });

prisma.$on("query", (event) => {
  prismaLogger.debug({
    query: event.query,
    duration_ms: event.duration,
    params: event.params,
  });
});

prisma.$on("error", (event) => {
  prismaLogger.error({
    error: event.target.message,
    query: event.target.query,
  });
});

const logger = pino({
  serializers: {
    err: (err: Error) => ({
      message: err.message,
      name: err.name,
      stack: process.env.NODE_ENV === "development" ? err.stack : undefined,
      code: (err as any).code,
    }),
  },
});

const logger = pino({
  level: "info",
  redact: {
    paths: [
      "req.headers.authorization",
      "req.headers.cookie",
      "req.headers['x-api-key']",
      "*.password",
      "*.token",
      "*.secret",
      "*.apiKey",
      "body.Authorization",
      "body.cookie",
    ],
    censor: "[REDACTED]",
  },
});

const logger = pino({
  level: "info",
  transport: {
    target: "pino-roll",
    options: {
      file: "./logs/app.log",
      size: "10m",
      interval: "1d",
      maxFiles: 7,
      compress: true,
      mkdir: true,
    },
  },
});

process.on("uncaughtException", (err: Error, origin: string) => {
  logger.fatal(
    {
      err: { message: err.message, stack: err.stack, name: err.name },
      origin,
    },
    "Uncaught exception — process will exit"
  );
  setTimeout(() => process.exit(1), 1000);
});

process.on("unhandledRejection", (reason: unknown, promise: Promise<unknown>) => {
  logger.error(
    {
      reason: reason instanceof Error ? reason.message : String(reason),
      stack: reason instanceof Error ? reason.stack : undefined,
    },
    "Unhandled promise rejection"
  );
});

